class Solution:
    def longestValidParentheses(self, s):
        best = 0
        n = len(s)
        for i in range(n):
            bal = 0
            for j in range(i, n):
                bal += 1 if s[j] == '(' else -1
                if bal < 0:
                    break
                if bal == 0:
                    best = max(best, j - i + 1)
        return best

